-- Luke Chapter 21
-- Theme: The Widow's Offering, the Destruction of Jerusalem, and the Coming of the Son of Man
-- 38 verses

INSERT INTO chapters (book_id, chapter_number, overview, theme, key_word_original, key_word_meaning, outline)
SELECT b.id, 21,
  'Luke 21 opens with one of the most piercing contrasts in the Gospels: the observation of rich donors and a destitute widow at the Temple treasury (vv.1-4). The widow''s two mites (lepta, the smallest coins in circulation) constitute "all the living that she had" (hapanta ton bion — her entire livelihood), prompting Jesus to declare that she has given more than all the wealthy combined. The episode is not merely a lesson in generosity; it is a prophetic commentary on the Temple system itself — an institution that devours widows'' houses (20:47) while accumulating ornamental splendor. The widow''s total sacrifice of her livelihood into a doomed institution prepares the reader for the discourse that follows.' ||
  'The central section (vv.5-28) constitutes Luke''s version of the Olivet Discourse, though Luke sets it within the Temple courts rather than on the Mount of Olives (contrast Mark 13:3). The discourse moves through three phases: the nearterm persecution of the disciples (vv.12-19), the destruction of Jerusalem in AD 70 (vv.20-24), and the cosmic signs attending the eschatological coming of the Son of Man (vv.25-28). Luke is distinctive in his explicit reference to Jerusalem surrounded by armies (v.20), the fall of the city, the scattering of Jews among the nations, and "the times of the Gentiles" (kairoi ethnōn, v.24) — a period of Gentile dominion that has a divinely determined terminus. These features give Luke''s account a sharper historical focus than the parallels in Matthew 24 and Mark 13.' ||
  'The parable of the fig tree (vv.29-33) teaches the disciples to read the signs: as budding foliage signals the nearness of summer, so the unfolding of the predicted events signals the nearness of the kingdom of God. Jesus'' declaration that "this generation shall not pass away, till all be fulfilled" (v.32) has been interpreted variously: as the generation witnessing the fall of Jerusalem, the generation alive at the eschatological events, or "generation" in the sense of this type of people (the Jewish nation). The chapter''s concluding exhortation (vv.34-36) warns against the spiritual dangers of complacency: surfeiting, drunkenness, and the cares of life that dull eschatological alertness. The final verses (vv.37-38) paint a summary portrait of Jesus'' last days of public ministry — teaching daily in the Temple, withdrawing to the Mount of Olives at night, and drawing eager morning crowds.',
  'The Widow''s Offering, the Destruction of Jerusalem, and the Coming of the Son of Man',
  'παρατηρέω (paratēreō)',
  'paratēreō means to watch closely, observe carefully, keep one''s eyes upon — from para (alongside) and tēreō (to watch, guard). While the specific word does not appear in this chapter, the semantic field of watchfulness pervades the entire discourse. Jesus commands his disciples to "take heed" (blepete, v.8), to "look up" (anakupsate, v.28), and to "watch" (agrupneite, v.36 — literally, be sleepless). The chapter presents a theology of eschatological vigilance: the faithful community must watch the signs of the times with discerning eyes, neither deceived by false messiahs (v.8) nor paralyzed by fear (v.9), but standing firm in patient endurance (v.19) and prayerful alertness (v.36) until the redemption that draws near.',
  '["The Widow''s Two Mites: True Sacrifice Exposed (vv.1-4)","The Temple''s Doom Predicted (vv.5-6)","Signs, Persecutions, and the Disciples'' Mission (vv.7-19)","The Fall of Jerusalem and the Times of the Gentiles (vv.20-24)","Cosmic Signs and the Coming of the Son of Man (vv.25-28)","The Parable of the Fig Tree: Reading the Signs (vv.29-33)","Exhortation to Watchfulness and Summary of Jesus'' Final Days (vv.34-38)"]'
FROM books b WHERE b.name = 'Luke';

INSERT INTO verses (chapter_id, verse_number, kjv_text, original_text, transliteration, study_note, doctrinal_note)
SELECT c.id, v.verse_number, v.kjv_text, v.original_text, v.transliteration, v.study_note, v.doctrinal_note
FROM chapters c
JOIN books b ON c.book_id = b.id
CROSS JOIN (VALUES
  (1, 'And he looked up, and saw the rich men casting their gifts into the treasury.', 'Ἀναβλέψας δὲ εἶδεν τοὺς βάλλοντας εἰς τὸ γαζοφυλάκιον τὰ δῶρα αὐτῶν πλουσίους.', 'Anablepsas de eiden tous ballontas eis to gazophulakion ta dōra autōn plousious.', 'The scene follows immediately from the denunciation of scribes who "devour widows'' houses" (20:47). "He looked up" (Anablepsas — having looked up, the same word used for receiving sight in 18:42) — Jesus observes with penetrating insight, not casual glance. "The treasury" (to gazophulakion — the treasury, from gaza/treasure + phulakē/guard; the collection receptacles in the Women''s Court of the Temple, traditionally thirteen trumpet-shaped chests for various offerings). "The rich men casting their gifts" (tous ballontas...plousious — the wealthy ones throwing in their gifts) — the imperfect sense of ongoing action suggests Jesus watched multiple donors making their contributions.', NULL),
  (2, 'And he saw also a certain poor widow casting in thither two mites.', 'εἶδεν δέ τινα χήραν πενιχρὰν βάλλουσαν ἐκεῖ λεπτὰ δύο,', 'eiden de tina chēran penichran ballousan ekei lepta duo,', '"A certain poor widow" (chēran penichran — a destitute widow; penichros is stronger than ptōchos: not merely poor but impoverished, appearing only here in the NT). "Two mites" (lepta duo — two lepta, the smallest bronze coins in circulation, each worth 1/128 of a denarius; a day''s wage was one denarius). Mark 12:42 adds the explanatory gloss that two lepta equal one quadrans (Roman coin), confirming the utterly negligible monetary value. The contrast between the wealthy donors'' gifts and her two nearly worthless coins sets up Jesus'' revolutionary valuation in vv.3-4.', NULL),
  (3, 'And he said, Of a truth I say unto you, that this poor widow hath cast in more than they all:', 'καὶ εἶπεν, Ἀληθῶς λέγω ὑμῖν ὅτι ἡ χήρα αὕτη ἡ πτωχὴ πλεῖον πάντων ἔβαλεν·', 'kai eipen, Alēthōs legō humin hoti hē chēra hautē hē ptōchē pleion pantōn ebalen;', '"Of a truth" (Alēthōs — truly, certainly; a solemn introductory formula). "This poor widow" (hē chēra hautē hē ptōchē — this widow, the poor one; now ptōchē, the more common word for poor, is used alongside the earlier penichran). "More than they all" (pleion pantōn — more than all of them) — Jesus establishes an economy of sacrifice that measures giving not by the amount deposited but by the cost to the giver. The rich gave from surplus; she gave from deficit. The pronouncement overturns the visible evidence: numerically she gave the least; sacrificially she gave the most.', NULL),
  (4, 'For all these have of their abundance cast in unto the offerings of God: but she of her penury hath cast in all the living that she had.', 'πάντες γὰρ οὗτοι ἐκ τοῦ περισσεύοντος αὐτοῖς ἔβαλον εἰς τὰ δῶρα, αὕτη δὲ ἐκ τοῦ ὑστερήματος αὐτῆς πάντα τὸν βίον ὃν εἶχεν ἔβαλεν.', 'pantes gar houtoi ek tou perisseuontos autois ebalon eis ta dōra, hautē de ek tou husterēmatos autēs panta ton bion hon eichen ebalen.', '"Of their abundance" (ek tou perisseuontos — from their surplus, from what was overflowing) versus "of her penury" (ek tou husterēmatos — from her deficit, from her lack, from what was wanting). "All the living that she had" (panta ton bion hon eichen — all the livelihood that she had; bios means life in the sense of the means of living, one''s resources for survival). She gave not merely all her money but her entire means of sustenance. The phrase echoes the language of total sacrifice. Coming after 20:47 (scribes devouring widows'' houses), the episode carries prophetic irony: the Temple system consumes the very people God commanded it to protect (Deut 14:29; 26:12).', NULL),
  (5, 'And as some spake of the temple, how it was adorned with goodly stones and gifts, he said,', 'Καί τινων λεγόντων περὶ τοῦ ἱεροῦ, ὅτι λίθοις καλοῖς καὶ ἀναθήμασιν κεκόσμηται, εἶπεν,', 'Kai tinōn legontōn peri tou hierou, hoti lithois kalois kai anathēmasin kekosmētai, eipen,', '"Some spake of the temple" (tinōn legontōn — certain ones saying; Luke does not identify the speakers as disciples specifically) — the admiration of the Temple''s beauty provides the occasion for Jesus'' devastating prediction. "Goodly stones" (lithois kalois — beautiful stones; Herod''s Temple used massive white limestone blocks, some measuring 40 feet long and weighing over 100 tons, according to Josephus). "Gifts" (anathēmasin — votive offerings, dedicated gifts; not the same word as anathema/curse, though spelled similarly; these were the golden ornaments, shields, and chains hung in the Temple). "Was adorned" (kekosmētai — had been adorned, perfect tense: stood in its completed, decorated state) — the Temple was considered one of the wonders of the ancient world.', NULL),
  (6, 'As for these things which ye behold, the days will come, in the which there shall not be left one stone upon another, that shall not be thrown down.', 'Ταῦτα ἃ θεωρεῖτε, ἐλεύσονται ἡμέραι ἐν αἷς οὐκ ἀφεθήσεται λίθος ἐπὶ λίθῳ ὃς οὐ καταλυθήσεται.', 'Tauta ha theōreite, eleusontai hēmerai en hais ouk aphethēsetai lithos epi lithō hos ou kataluthēsetai.', '"These things which ye behold" (Tauta ha theōreite — these things you are gazing at; theōreō implies careful, sustained looking) — Jesus redirects their admiring gaze toward an apocalyptic horizon. "Not be left one stone upon another" (ouk aphethēsetai lithos epi lithō — not one stone will be left upon a stone) — total demolition. "Thrown down" (kataluthēsetai — will be destroyed, demolished, loosened down; kata + luō). This was fulfilled with devastating literalness in AD 70 when Titus''s legions systematically dismantled the Temple, with soldiers reportedly prying apart stones to retrieve gold that had melted into the crevices during the fire. The prediction is all the more striking given the massive size of the stones that the speakers were admiring.', NULL),
  (7, 'And they asked him, saying, Master, but when shall these things be? and what sign will there be when these things shall come to pass?', 'Ἐπηρώτησαν δὲ αὐτὸν λέγοντες, Διδάσκαλε, πότε οὖν ταῦτα ἔσται; καὶ τί τὸ σημεῖον ὅταν μέλλῃ ταῦτα γίνεσθαι;', 'Epērōtēsan de auton legontes, Didaskale, pote oun tauta estai? kai ti to sēmeion hotan mellē tauta ginesthai?', '"Master" (Didaskale — Teacher) — the question is dual: "when?" (pote — at what time) and "what sign?" (ti to sēmeion — what is the sign). Unlike Matthew 24:3, which adds "and of thy coming, and of the end of the world," Luke''s question concerns only "these things" (tauta) — the destruction of the Temple. This narrower focus is significant for Luke''s redaction: he will carefully distinguish the fall of Jerusalem (a near-term historical event) from the eschatological coming of the Son of Man (a future cosmic event). Jesus''s answer addresses the sign-question but deliberately frustrates the timing-question.', NULL),
  (8, 'And he said, Take heed that ye be not deceived: for many shall come in my name, saying, I am Christ; and the time draweth near: go ye not therefore after them.', 'ὁ δὲ εἶπεν, Βλέπετε μὴ πλανηθῆτε· πολλοὶ γὰρ ἐλεύσονται ἐπὶ τῷ ὀνόματί μου λέγοντες, Ἐγώ εἰμι, καί, Ὁ καιρὸς ἤγγικεν· μὴ πορευθῆτε ὀπίσω αὐτῶν.', 'ho de eipen, Blepete mē planēthēte; polloi gar eleusontai epi tō onomati mou legontes, Egō eimi, kai, Ho kairos ēngiken; mē poreuthēte opisō autōn.', '"Take heed that ye be not deceived" (Blepete mē planēthēte — watch out lest you be led astray; planaō is the root of "planet" — wandering stars) — the first imperative of the discourse is a warning against deception, not against suffering. "I am Christ" (Egō eimi — I am he; the absolute "I am" echoing the divine name, making these claims blasphemous usurpations). Luke uniquely adds "the time draweth near" (Ho kairos ēngiken — the appointed time has drawn near) — false messiahs will accompany their claims with eschatological urgency. "Go ye not therefore after them" (mē poreuthēte opisō autōn — do not go after them) — a direct prohibition against following eschatological pretenders. Josephus records multiple such figures in the decades before AD 70.', NULL),
  (9, 'But when ye shall hear of wars and commotions, be not terrified: for these things must first come to pass; but the end is not by and by.', 'ὅταν δὲ ἀκούσητε πολέμους καὶ ἀκαταστασίας, μὴ πτοηθῆτε· δεῖ γὰρ ταῦτα γενέσθαι πρῶτον, ἀλλ'' οὐκ εὐθέως τὸ τέλος.', 'hotan de akousēte polemous kai akatastasias, mē ptoēthēte; dei gar tauta genesthai prōton, all'' ouk eutheōs to telos.', '"Wars and commotions" (polemous kai akatastasias — wars and instabilities/upheavals; akatastasia means disorder, political tumult, anarchy; used by Paul in 1 Cor 14:33 and 2 Cor 6:5). "Be not terrified" (mē ptoēthēte — do not be frightened, do not be startled; ptoeō appears only here and 24:37 in the NT, suggesting sudden, paralyzing fear). "Must first come to pass" (dei...genesthai prōton — it is divinely necessary for these things to happen first; dei is the word of divine necessity). "The end is not by and by" (ouk eutheōs to telos — not immediately the end) — wars and political upheavals are not signs of the end but precursors that must be endured. This caution against premature eschatological calculation is distinctively Lucan.', NULL),
  (10, 'Then said he unto them, Nation shall rise against nation, and kingdom against kingdom:', 'Τότε ἔλεγεν αὐτοῖς, Ἐγερθήσεται ἔθνος ἐπ'' ἔθνος καὶ βασιλεία ἐπὶ βασιλείαν·', 'Tote elegen autois, Egerthēsetai ethnos ep'' ethnos kai basileia epi basileian;', '"Nation shall rise against nation, and kingdom against kingdom" (Egerthēsetai ethnos ep'' ethnos kai basileia epi basileian — nation will be raised against nation and kingdom against kingdom) — the language echoes Isaiah 19:2 and 2 Chronicles 15:6 (LXX), indicating that Jesus frames the coming conflicts in the prophetic tradition of divine judgment. The passive voice (egerthēsetai — will be raised up) implies divine sovereignty over international conflicts. The decades before AD 70 saw massive upheavals: the Jewish revolt against Rome (AD 66-70), civil wars following Nero''s death (AD 68-69, the "Year of the Four Emperors"), and conflicts across the Roman Empire.', NULL),
  (11, 'And great earthquakes shall be in divers places, and famines, and pestilences; and fearful sights and great signs shall there be from heaven.', 'σεισμοί τε μεγάλοι καὶ κατὰ τόπους λιμοὶ καὶ λοιμοὶ ἔσονται, φόβητρά τε καὶ ἀπ'' οὐρανοῦ σημεῖα μεγάλα ἔσται.', 'seismoi te megaloi kai kata topous limoi kai loimoi esontai, phobētra te kai ap'' ouranou sēmeia megala estai.', '"Great earthquakes" (seismoi megaloi — large earthquakes; seismos from seiō, to shake) "in divers places" (kata topous — throughout various locations). "Famines and pestilences" (limoi kai loimoi — famines and plagues; the near-homophony in Greek creates a rhetorical pairing). Acts 11:28 records the fulfillment of a great famine under Claudius. "Fearful sights" (phobētra — terrifying phenomena; a hapax legomenon in the NT) "and great signs from heaven" (sēmeia megala — great portents) — Josephus records extraordinary celestial signs before Jerusalem''s fall: a star resembling a sword over the city, a comet visible for a year, and a light around the altar at night (Jewish War 6.5.3). These phenomena serve as both historical precursors and typological previews of the cosmic disturbances in vv.25-26.', NULL),
  (12, 'But before all these, they shall lay their hands on you, and persecute you, delivering you up to the synagogues, and into prisons, being brought before kings and rulers for my name''s sake.', 'πρὸ δὲ τούτων πάντων ἐπιβαλοῦσιν ἐφ'' ὑμᾶς τὰς χεῖρας αὐτῶν καὶ διώξουσιν, παραδιδόντες εἰς τὰς συναγωγὰς καὶ φυλακάς, ἀπαγομένους ἐπὶ βασιλεῖς καὶ ἡγεμόνας ἕνεκεν τοῦ ὀνόματός μου·', 'pro de toutōn pantōn epibalousin eph'' humas tas cheiras autōn kai diōxousin, paradidontes eis tas sunagōgas kai phulakas, apagomenous epi basileis kai hēgemonas heneken tou onomatos mou;', '"But before all these" (pro de toutōn pantōn — before all these things) — chronologically, persecution precedes the cosmic and political upheavals. "Lay their hands on you" (epibalousin...tas cheiras — they will throw their hands upon you, a violent seizure). "Delivering you up to the synagogues, and into prisons" (paradidontes eis tas sunagōgas kai phulakas — handing over to synagogues and prisons) — the verb paradidōmi (to hand over) is the same used for Judas''s betrayal and Jesus''s delivery to Pilate; the disciples will share their master''s experience. "Before kings and rulers" — Acts records fulfillments: Peter and John before the Sanhedrin (Acts 4), Paul before Felix, Festus, and Agrippa (Acts 24-26). "For my name''s sake" (heneken tou onomatos mou) — the cause of persecution is Christological.', NULL),
  (13, 'And it shall turn to you for a testimony.', 'ἀποβήσεται ὑμῖν εἰς μαρτύριον.', 'apobēsetai humin eis marturion.', '"It shall turn to you for a testimony" (apobēsetai humin eis marturion — it will result for you as a testimony; apobainō means to come out, to result, to turn out). The persecution itself becomes the occasion for witness (marturion — testimony, the root of "martyr"). What appears to be disaster is reframed as divine opportunity. The hostile courtroom becomes a pulpit; the accusation becomes an occasion for proclamation. This is characteristically Lucan: suffering and witness are inseparable in Luke-Acts. The history of the early church demonstrates this principle repeatedly — persecution scattered the church, and the scattering produced evangelism (Acts 8:1-4).', NULL),
  (14, 'Settle it therefore in your hearts, not to meditate before what ye shall answer:', 'θέτε οὖν ἐν ταῖς καρδίαις ὑμῶν μὴ προμελετᾶν ἀπολογηθῆναι·', 'thete oun en tais kardiais humōn mē promeletan apologēthēnai;', '"Settle it therefore in your hearts" (thete oun en tais kardiais humōn — place it therefore in your hearts, determine it, resolve it; tithēmi in the imperative: make this a settled decision). "Not to meditate before" (mē promeletan — not to practice beforehand, not to rehearse; pro + meletaō = to practice in advance) "what ye shall answer" (apologēthēnai — to make a defense, an apologia). The command is counterintuitive: faced with life-threatening trials, the natural instinct is to prepare one''s defense meticulously. Jesus prohibits this not because preparation is sinful but because a higher resource is available (v.15). The same principle appears in Matthew 10:19-20, where the Spirit of the Father is the promised advocate.', NULL),
  (15, 'For I will give you a mouth and wisdom, which all your adversaries shall not be able to gainsay nor resist.', 'ἐγὼ γὰρ δώσω ὑμῖν στόμα καὶ σοφίαν ᾗ οὐ δυνήσονται ἀντιστῆναι ἢ ἀντειπεῖν ἅπαντες οἱ ἀντικείμενοι ὑμῖν.', 'egō gar dōsō humin stoma kai sophian hē ou dunēsontai antistēnai ē anteipein hapantes hoi antikeimenoi humin.', '"I will give you" (egō...dōsō — emphatic first person: I myself will give) "a mouth and wisdom" (stoma kai sophian — both the capacity to speak and the content of what to say; "mouth" as metonymy for eloquent speech). "Which all your adversaries shall not be able to gainsay nor resist" (ou dunēsontai antistēnai ē anteipein — will not be able to stand against or speak against; a double impossibility). Luke uniquely attributes this gift directly to Jesus rather than to the Holy Spirit (cf. Matt 10:20; Mark 13:11), though Luke elsewhere makes Jesus and the Spirit''s work inseparable. Acts 6:10 records the fulfillment with Stephen: "they were not able to resist the wisdom and the spirit by which he spake."', NULL),
  (16, 'And ye shall be betrayed both by parents, and brethren, and kinsfolks, and friends; and some of you shall they cause to be put to death.', 'παραδοθήσεσθε δὲ καὶ ὑπὸ γονέων καὶ ἀδελφῶν καὶ συγγενῶν καὶ φίλων, καὶ θανατώσουσιν ἐξ ὑμῶν,', 'paradothēsesthe de kai hupo goneōn kai adelphōn kai sungenōn kai philōn, kai thanatōsousin ex humōn,', '"Betrayed" (paradothēsesthe — you will be handed over; the same paradidōmi used for Judas''s betrayal) — the disciples will be betrayed not by strangers but by their most intimate relations. "Parents, brethren, kinsfolks, and friends" (goneōn, adelphōn, sungenōn, philōn) — the list comprehensively covers every sphere of trusted relationship: family of origin, siblings, extended kin, and chosen companions. "Some of you shall they cause to be put to death" (thanatōsousin ex humōn — they will put to death some from among you) — martyrdom is predicted explicitly. James the brother of John was martyred (Acts 12:2), Stephen was stoned (Acts 7), and tradition records the martyrdom of most apostles. The prophecy warns that faithfulness to Christ may sever the deepest human bonds (cf. 12:51-53).', NULL),
  (17, 'And ye shall be hated of all men for my name''s sake.', 'καὶ ἔσεσθε μισούμενοι ὑπὸ πάντων διὰ τὸ ὄνομά μου·', 'kai esesthe misoumenoi hupo pantōn dia to onoma mou;', '"Hated of all men" (misoumenoi hupo pantōn — being hated by all; the periphrastic future esesthe misoumenoi emphasizes the ongoing, continuous nature of the hatred) — universal social hostility. "For my name''s sake" (dia to onoma mou — on account of my name) — the cause is not the disciples'' moral failure or social offense but their identification with Jesus. His name becomes the lightning rod for the world''s hostility. The promise that follows in v.18 makes this hatred bearable: it cannot ultimately harm them. The pattern of Christ — rejected by all yet vindicated by God — is reproduced in his followers.', NULL),
  (18, 'But there shall not an hair of your head perish.', 'καὶ θρὶξ ἐκ τῆς κεφαλῆς ὑμῶν οὐ μὴ ἀπόληται.', 'kai thrix ek tēs kephalēs humōn ou mē apolētai.', '"Not an hair of your head perish" (thrix ek tēs kephalēs humōn ou mē apolētai — a hair from your head will certainly not perish; ou mē with the subjunctive: the strongest possible negation in Greek). This promise stands in apparent paradox with v.16 ("some of you shall they cause to be put to death"). The resolution is eschatological: physical death is not ultimate loss. Jesus has already taught "fear not them which kill the body" (12:4). The hair of the head represents the most insignificant part of a person; if even that is preserved in God''s care, the whole person is secure. The promise echoes 12:7 ("the very hairs of your head are all numbered") and anticipates the resurrection hope that undergirds the entire discourse.', NULL),
  (19, 'In your patience possess ye your souls.', 'ἐν τῇ ὑπομονῇ ὑμῶν κτήσασθε τὰς ψυχὰς ὑμῶν.', 'en tē hupomonē humōn ktēsasthe tas psuchas humōn.', '"In your patience" (en tē hupomonē humōn — in your patient endurance; hupomonē from hupo + menō, to remain under, to bear up under pressure without collapsing) — not passive resignation but active, resolute endurance under suffering. "Possess ye your souls" (ktēsasthe tas psuchas humōn — gain, acquire, take possession of your souls/lives; ktaomai means to acquire, to win). The imperative is significant: endurance is the means by which true life is gained. Some manuscripts read the future indicative (ktēsesthe — "you will gain") rather than the imperative, but the meaning is similar. This verse is the summary exhortation for the persecution section (vv.12-19): the response to betrayal, hatred, and martyrdom is not retaliation, flight, or despair but steadfast endurance that secures the soul.', NULL),
  (20, 'And when ye shall see Jerusalem compassed with armies, then know that the desolation thereof is nigh.', 'Ὅταν δὲ ἴδητε κυκλουμένην ὑπὸ στρατοπέδων Ἰερουσαλήμ, τότε γνῶτε ὅτι ἤγγικεν ἡ ἐρήμωσις αὐτῆς.', 'Hotan de idēte kukloumenēn hupo stratopedōn Ierousalēm, tote gnōte hoti ēngiken hē erēmōsis autēs.', '"Jerusalem compassed with armies" (kukloumenēn hupo stratopedōn Ierousalēm — Jerusalem being surrounded by armed encampments; kukloō = to encircle; stratopedōn = military camps/armies) — Luke''s version is far more historically specific than Mark''s "abomination of desolation" (Mark 13:14). The Roman siege of Jerusalem began in AD 66 under Cestius Gallus, was briefly lifted, then resumed with devastating finality under Vespasian and Titus (AD 67-70). "The desolation thereof" (hē erēmōsis — the devastation, the making desolate) — the same word family (erēmos/erēmōsis) used in the LXX of Daniel 9:27 and 11:31 for the "abomination of desolation." Luke interprets Daniel''s prophecy as finding fulfillment in Rome''s destruction of Jerusalem.', NULL),
  (21, 'Then let them which are in Judaea flee to the mountains; and let them which are in the midst of it depart out; and let not them that are in the countries enter thereinto.', 'τότε οἱ ἐν τῇ Ἰουδαίᾳ φευγέτωσαν εἰς τὰ ὄρη, καὶ οἱ ἐν μέσῳ αὐτῆς ἐκχωρείτωσαν, καὶ οἱ ἐν ταῖς χώραις μὴ εἰσερχέσθωσαν εἰς αὐτήν·', 'tote hoi en tē Ioudaia pheugetōsan eis ta orē, kai hoi en mesō autēs ekchōreitōsan, kai hoi en tais chōrais mē eiserchesthōsan eis autēn;', 'Three imperatives of urgent escape: (1) "flee to the mountains" (pheugetōsan eis ta orē — those in Judaea must flee to the highland regions); (2) "let them which are in the midst of it depart out" (ekchōreitōsan — let them withdraw; ekchōreō, a hapax in the NT, means to depart from a region entirely); (3) "let not them that are in the countries enter thereinto" (mē eiserchesthōsan — let them not enter into the city; those in the rural districts must not seek refuge in Jerusalem''s walls). Eusebius records (Ecclesiastical History 3.5.3) that the Christian community in Jerusalem heeded this warning and fled to Pella in the Transjordan before Titus''s siege tightened, thus preserving the Jerusalem church.', NULL),
  (22, 'For these be the days of vengeance, that all things which are written may be fulfilled.', 'ὅτι ἡμέραι ἐκδικήσεως αὗταί εἰσιν, τοῦ πλησθῆναι πάντα τὰ γεγραμμένα.', 'hoti hēmerai ekdikēseōs hautai eisin, tou plēsthēnai panta ta gegrammena.', '"Days of vengeance" (hēmerai ekdikēseōs — days of vindication/retribution; ekdikēsis from ek + dikē, justice executed) — the language echoes Hosea 9:7 (LXX: "the days of vengeance have come") and Deuteronomy 32:35 ("the day of vengeance"). Jerusalem''s destruction is framed as divine judgment, not merely Roman military action. "That all things which are written may be fulfilled" (tou plēsthēnai panta ta gegrammena — so that all the things having been written may be filled up/completed) — the destruction fulfills a prophetic script. Jesus sees in Jerusalem''s coming ruin the culmination of the prophetic warnings spanning from Moses through the prophets: covenant judgment upon persistent unfaithfulness (Deut 28:49-57; Jer 6:1-8; Dan 9:26).', NULL),
  (23, 'But woe unto them that are with child, and to them that give suck, in those days! for there shall be great distress in the land, and wrath upon this people.', 'οὐαὶ ταῖς ἐν γαστρὶ ἐχούσαις καὶ ταῖς θηλαζούσαις ἐν ἐκείναις ταῖς ἡμέραις· ἔσται γὰρ ἀνάγκη μεγάλη ἐπὶ τῆς γῆς καὶ ὀργὴ τῷ λαῷ τούτῳ·', 'ouai tais en gastri echousais kai tais thēlazousais en ekeinais tais hēmerais; estai gar anankē megalē epi tēs gēs kai orgē tō laō toutō;', '"Woe unto them that are with child, and to them that give suck" (ouai tais en gastri echousais kai tais thēlazousais — woe to the pregnant and the nursing) — not a curse but a lament of compassion: the physically vulnerable will suffer most in the siege and flight. Josephus records the horrifying conditions during the siege, including the account of Mary of Beth-ezob who, in her starvation, consumed her own infant (Jewish War 6.3.4). "Great distress in the land" (anankē megalē — great necessity, extreme pressure, dire constraint). "Wrath upon this people" (orgē tō laō toutō — wrath upon this people) — Luke uniquely specifies "this people" (Israel), making explicit the covenantal nature of the judgment. The destruction is not random catastrophe but divine orgē directed at covenant unfaithfulness.', NULL),
  (24, 'And they shall fall by the edge of the sword, and shall be led away captive into all nations: and Jerusalem shall be trodden down of the Gentiles, until the times of the Gentiles be fulfilled.', 'καὶ πεσοῦνται στόματι μαχαίρης καὶ αἰχμαλωτισθήσονται εἰς τὰ ἔθνη πάντα, καὶ Ἰερουσαλὴμ ἔσται πατουμένη ὑπὸ ἐθνῶν, ἄχρι οὗ πληρωθῶσιν καιροὶ ἐθνῶν.', 'kai pesountai stomati machairēs kai aichmalōtisthēsontai eis ta ethnē panta, kai Ierousalēm estai patoumenē hupo ethnōn, achri hou plērōthōsin kairoi ethnōn.', '"Fall by the edge of the sword" (pesountai stomati machairēs — will fall by the mouth of the sword; a Hebrew idiom preserved in the LXX, cf. Jer 21:7). Josephus estimates 1.1 million deaths during the siege (Jewish War 6.9.3). "Led away captive into all nations" (aichmalōtisthēsontai eis ta ethnē panta — will be taken captive into all the nations) — Josephus records 97,000 captives taken. "Jerusalem shall be trodden down of the Gentiles" (estai patoumenē hupo ethnōn — will be being trampled by nations; the periphrastic future: ongoing trampling) — the city passes under Gentile control. "Until the times of the Gentiles be fulfilled" (achri hou plērōthōsin kairoi ethnōn — until the seasons/appointed times of the nations are fulfilled) — this uniquely Lucan phrase implies a divinely determined duration for Gentile dominion over Jerusalem, after which that dominion ends. The phrase suggests both judgment and hope: Gentile trampling has a terminus.', NULL),
  (25, 'And there shall be signs in the sun, and in the moon, and in the stars; and upon the earth distress of nations, with perplexity; the sea and the waves roaring;', 'Καὶ ἔσονται σημεῖα ἐν ἡλίῳ καὶ σελήνῃ καὶ ἄστροις, καὶ ἐπὶ τῆς γῆς συνοχὴ ἐθνῶν ἐν ἀπορίᾳ ἤχους θαλάσσης καὶ σάλου,', 'Kai esontai sēmeia en hēliō kai selēnē kai astrois, kai epi tēs gēs sunochē ethnōn en aporia ēchous thalassēs kai salou,', '"Signs in the sun, and in the moon, and in the stars" (sēmeia en hēliō kai selēnē kai astrois) — the discourse now shifts from the historical fall of Jerusalem (vv.20-24) to the cosmic eschatological consummation. The language draws heavily on Isaiah 13:10, Joel 2:30-31, and Isaiah 34:4. "Distress of nations, with perplexity" (sunochē ethnōn en aporia — anguish of nations in helplessness; sunochē = compression, anguish, from sunechō/to press together; aporia = no way out, perplexity, from a-negative + poros/way). "The sea and the waves roaring" (ēchous thalassēs kai salou — the roaring of sea and surging; the sea in OT imagery represents chaos, primordial disorder, and divine judgment, cf. Ps 46:3; Isa 17:12-13).', NULL),
  (26, 'Men''s hearts failing them for fear, and for looking after those things which are coming on the earth: for the powers of heaven shall be shaken.', 'ἀποψυχόντων ἀνθρώπων ἀπὸ φόβου καὶ προσδοκίας τῶν ἐπερχομένων τῇ οἰκουμένῃ· αἱ γὰρ δυνάμεις τῶν οὐρανῶν σαλευθήσονται.', 'apopsuchontōn anthrōpōn apo phobou kai prosdokias tōn eperchomenōn tē oikoumenē; hai gar dunameis tōn ouranōn saleuthēsontai.', '"Hearts failing them for fear" (apopsuchontōn apo phobou — fainting away from fear; apopsuchō is a hapax legomenon in the NT, meaning to breathe out, expire, faint; the word suggests a literal dying of terror). "Looking after those things which are coming" (prosdokias tōn eperchomenōn — in expectation of the things approaching upon) "the earth" (tē oikoumenē — the inhabited world; a Lucan favorite, used for the entire civilized world). "The powers of heaven shall be shaken" (hai dunameis tōn ouranōn saleuthēsontai — the powers of the heavens will be shaken) — dunameis may refer to celestial bodies (sun, moon, stars as "powers") or to angelic/spiritual forces governing the cosmos. The cosmic framework that humanity takes for granted as stable will be disrupted, removing every false security.', NULL),
  (27, 'And then shall they see the Son of man coming in a cloud with power and great glory.', 'καὶ τότε ὄψονται τὸν Υἱὸν τοῦ ἀνθρώπου ἐρχόμενον ἐν νεφέλῃ μετὰ δυνάμεως καὶ δόξης πολλῆς.', 'kai tote opsontai ton Huion tou anthrōpou erchomenon en nephelē meta dunameōs kai doxēs pollēs.', '"Then shall they see" (tote opsontai — then they will see; the subject is universal: all humanity) "the Son of man coming in a cloud" (ton Huion tou anthrōpou erchomenon en nephelē — the Son of Man coming in a cloud) — direct allusion to Daniel 7:13-14, where "one like the Son of man" comes "with the clouds of heaven" to receive universal dominion from the Ancient of Days. "With power and great glory" (meta dunameōs kai doxēs pollēs — with power and much glory) — the contrast with Jesus''s present humble state could not be sharper. The one who will soon be arrested, tried, and crucified will return in visible, cosmic, undeniable glory. The cloud (nephelē) is the theophanic cloud of divine presence (Exod 13:21; 1 Kgs 8:10-11; cf. Luke 9:34-35 at the Transfiguration).', NULL),
  (28, 'And when these things begin to come to pass, then look up, and lift up your heads; for your redemption draweth nigh.', 'ἀρχομένων δὲ τούτων γίνεσθαι ἀνακύψατε καὶ ἐπάρατε τὰς κεφαλὰς ὑμῶν, διότι ἐγγίζει ἡ ἀπολύτρωσις ὑμῶν.', 'archomenōn de toutōn ginesthai anakupsate kai eparate tas kephalas humōn, dioti engizei hē apolutrōsis humōn.', '"When these things begin to come to pass" (archomenōn toutōn ginesthai — when these things are beginning to happen; the genitive absolute marks the temporal condition). "Look up, and lift up your heads" (anakupsate kai eparate tas kephalas humōn — stand upright and raise your heads) — the posture is the opposite of the terror described in v.26. While the world faints with fear, the disciples are to stand tall. The double imperative demands both physical and spiritual composure. "Your redemption draweth nigh" (engizei hē apolutrōsis humōn — your redemption draws near; apolutrōsis = release, deliverance, ransom-liberation; from apo + lutrōsis, from lutron/ransom). For the disciples, the same events that terrify the world signal their liberation. What is judgment for the impenitent is redemption for the faithful.', NULL),
  (29, 'And he spake to them a parable; Behold the fig tree, and all the trees;', 'Καὶ εἶπεν παραβολὴν αὐτοῖς· Ἴδετε τὴν συκῆν καὶ πάντα τὰ δένδρα·', 'Kai eipen parabolēn autois; Idete tēn sukēn kai panta ta dendra;', '"He spake to them a parable" (eipen parabolēn — he told a parable) — after the weighty prophetic discourse, Jesus turns to an agricultural illustration. "Behold the fig tree, and all the trees" (Idete tēn sukēn kai panta ta dendra — look at the fig tree and all the trees) — Luke adds "and all the trees" to Mark''s fig tree alone (Mark 13:28), universalizing the illustration beyond any specific symbolic identification of the fig tree with Israel. The point is observational: any deciduous tree demonstrates the principle. In Palestine, the fig tree''s spring budding was one of the most visible harbingers of approaching summer, its large leaves emerging dramatically after winter dormancy.', NULL),
  (30, 'When they now shoot forth, ye see and know of your own selves that summer is now nigh at hand.', 'ὅταν προβάλωσιν ἤδη, βλέποντες ἀφ'' ἑαυτῶν γινώσκετε ὅτι ἤδη ἐγγὺς τὸ θέρος ἐστίν·', 'hotan probalōsin ēdē, blepontes aph'' heautōn ginōskete hoti ēdē engus to theros estin;', '"When they now shoot forth" (hotan probalōsin — when they put forth leaves, when they sprout; proballō = to throw forward, to put forth new growth) — the trees'' budding is an observable, empirical sign that requires no special revelation to interpret. "Ye see and know of your own selves" (blepontes aph'' heautōn ginōskete — seeing, you know from yourselves, of your own accord) — the knowledge is self-evident, requiring no teacher. "Summer is now nigh at hand" (ēdē engus to theros estin — already near is the summer; theros from therō/to heat) — the sign and what it signifies are connected by natural, observable causation. Jesus draws an analogy: just as natural signs indicate natural seasons, prophetic signs indicate eschatological seasons.', NULL),
  (31, 'So likewise ye, when ye see these things come to pass, know ye that the kingdom of God is nigh at hand.', 'οὕτως καὶ ὑμεῖς, ὅταν ἴδητε ταῦτα γινόμενα, γινώσκετε ὅτι ἐγγύς ἐστιν ἡ βασιλεία τοῦ Θεοῦ.', 'houtōs kai humeis, hotan idēte tauta ginomena, ginōskete hoti engus estin hē basileia tou Theou.', '"So likewise ye" (houtōs kai humeis — thus also you) — the application of the parable. "When ye see these things come to pass" (hotan idēte tauta ginomena — when you see these things happening) — "these things" encompasses the signs described in the discourse: persecution, Jerusalem''s fall, cosmic disturbances. "The kingdom of God is nigh at hand" (engus estin hē basileia tou Theou — the kingdom of God is near) — Luke uniquely substitutes "the kingdom of God" for Mark''s "it is near, even at the doors" (Mark 13:29) and Matthew''s "it is near" (Matt 24:33). This is a distinctively Lucan emphasis: the signs point not merely to the Son of Man''s coming but to the full manifestation of God''s kingdom. The kingdom is already present in Jesus''s ministry (17:21) but awaits its consummation.', NULL),
  (32, 'Verily I say unto you, This generation shall not pass away, till all be fulfilled.', 'ἀμὴν λέγω ὑμῖν ὅτι οὐ μὴ παρέλθῃ ἡ γενεὰ αὕτη ἕως ἂν πάντα γένηται.', 'amēn legō humin hoti ou mē parelthē hē genea hautē heōs an panta genētai.', '"This generation" (hē genea hautē — this generation) — the most debated phrase in the discourse. Three primary interpretations: (1) the contemporaneous generation that will witness Jerusalem''s destruction in AD 70 — the most natural temporal reading and supported by the fact that vv.20-24 describe events fulfilled within 40 years; (2) the generation alive at the time of the eschatological signs — making it a statement about the rapidity of the final events once they begin; (3) "this generation" as "this kind of people" (genea in the sense of race or type, cf. Deut 32:5, 20) — the Jewish nation will persist until all is fulfilled. "Till all be fulfilled" (heōs an panta genētai — until all things come to pass) — the double negative ou mē with the subjunctive is the strongest asseverative form in Greek.', NULL),
  (33, 'Heaven and earth shall pass away: but my words shall not pass away.', 'ὁ οὐρανὸς καὶ ἡ γῆ παρελεύσονται, οἱ δὲ λόγοι μου οὐ μὴ παρελεύσονται.', 'ho ouranos kai hē gē pareleusontai, hoi de logoi mou ou mē pareleusontai.', '"Heaven and earth shall pass away" (ho ouranos kai hē gē pareleusontai — the heaven and the earth will pass away; parerchomai = to pass by, to come to an end) — the most stable, permanent elements of created reality are declared transient. "But my words shall not pass away" (hoi de logoi mou ou mē pareleusontai — but my words will certainly not pass away; again the double negative of strongest negation) — Jesus claims for his own words a permanence exceeding that of the created cosmos. This is an extraordinary Christological claim: only God''s word possesses such eternal, indestructible authority (Isa 40:8: "the word of our God shall stand for ever"). Jesus places his own speech on the level of divine utterance, implicitly claiming divine identity.', NULL),
  (34, 'And take heed to yourselves, lest at any time your hearts be overcharged with surfeiting, and drunkenness, and cares of this life, and so that day come upon you unawares.', 'Προσέχετε δὲ ἑαυτοῖς, μήποτε βαρηθῶσιν ὑμῶν αἱ καρδίαι ἐν κραιπάλῃ καὶ μέθῃ καὶ μερίμναις βιωτικαῖς, καὶ ἐπιστῇ ἐφ'' ὑμᾶς αἰφνίδιος ἡ ἡμέρα ἐκείνη·', 'Prosechete de heautois, mēpote barēthōsin humōn hai kardiai en kraipalē kai methē kai merimnais biōtikais, kai epistē eph'' humas aiphnidios hē hēmera ekeinē;', '"Take heed to yourselves" (Prosechete heautois — pay attention to yourselves, guard yourselves) — the final exhortation turns from external signs to internal condition. "Hearts be overcharged" (barēthōsin...hai kardiai — your hearts be weighed down, burdened, made heavy) with three dangers: (1) "surfeiting" (kraipalē — a hangover, the headache and nausea following excessive drinking; a word used in medical literature, only here in the NT); (2) "drunkenness" (methē — intoxication); (3) "cares of this life" (merimnais biōtikais — anxieties of daily living; merimna from merizō/to divide, the mind pulled in many directions by life''s demands). "That day come upon you unawares" (epistē...aiphnidios — may stand upon you suddenly; aiphnidios = unexpected, sudden; only here and 1 Thess 5:3 in the NT).', NULL),
  (35, 'For as a snare shall it come on all them that dwell on the face of the whole earth.', 'ὡς παγὶς γὰρ ἐπελεύσεται ἐπὶ πάντας τοὺς καθημένους ἐπὶ πρόσωπον πάσης τῆς γῆς.', 'hōs pagis gar epeleusetai epi pantas tous kathēmenous epi prosōpon pasēs tēs gēs.', '"As a snare" (hōs pagis — like a trap, a snare; pagis from pēgnumi/to fix, set; the image is of a bird-trap that springs shut suddenly, cf. Isa 24:17; Eccl 9:12) — the day will catch unprepared humanity as a trap catches unsuspecting prey. "On all them that dwell on the face of the whole earth" (epi pantas tous kathēmenous epi prosōpon pasēs tēs gēs — upon all those sitting upon the face of all the earth) — the universal scope: no region, nation, or individual will escape. "The face of the whole earth" echoes Genesis 1:29 and Isaiah 24:17 (LXX), giving the statement a creation-wide scope. The snare image reinforces v.34''s warning: the danger is not that the day will not come, but that it will come to those spiritually asleep.', NULL),
  (36, 'Watch ye therefore, and pray always, that ye may be accounted worthy to escape all these things that shall come to pass, and to stand before the Son of man.', 'ἀγρυπνεῖτε δὲ ἐν παντὶ καιρῷ δεόμενοι ἵνα κατισχύσητε ἐκφυγεῖν ταῦτα πάντα τὰ μέλλοντα γίνεσθαι, καὶ σταθῆναι ἔμπροσθεν τοῦ Υἱοῦ τοῦ ἀνθρώπου.', 'agrupneite de en panti kairō deomenoi hina katischusēte ekphugein tauta panta ta mellonta ginesthai, kai stathēnai emprosthen tou Huiou tou anthrōpou.', '"Watch ye" (agrupneite — be sleepless, keep awake, be vigilant; from a-negative + hupnos/sleep: literally, without sleep) — the strongest word for spiritual alertness. "Pray always" (en panti kairō deomenoi — in every season praying, making supplication) — echoing the parable of 18:1, persistent prayer is the means of maintaining eschatological alertness. "Accounted worthy to escape" (katischusēte ekphugein — to have strength to flee out of, to prevail in escaping; katischuō = to be strong enough, to overpower) — some manuscripts read "accounted worthy" (kataxiōthēte), but the meaning is similar: strength or worthiness to stand. "To stand before the Son of man" (stathēnai emprosthen tou Huiou tou anthrōpou — to stand in the presence of the Son of Man) — the ultimate goal: confident standing at the judgment, not cowering in terror (v.26) but standing in redeemed confidence (v.28).', NULL),
  (37, 'And in the day time he was teaching in the temple; and at night he went out, and abode in the mount that is called the mount of Olives.', 'Ἦν δὲ τὰς ἡμέρας ἐν τῷ ἱερῷ διδάσκων, τὰς δὲ νύκτας ἐξερχόμενος ηὐλίζετο εἰς τὸ ὄρος τὸ καλούμενον Ἐλαιῶν·', 'Ēn de tas hēmeras en tō hierō didaskōn, tas de nuktas exerchomenos ēulizeto eis to oros to kaloumenon Elaiōn;', '"In the day time he was teaching in the temple" (tas hēmeras en tō hierō didaskōn — during the days teaching in the Temple; the periphrastic imperfect Ēn...didaskōn emphasizes the habitual, ongoing nature of the activity). "At night he went out, and abode in the mount that is called the mount of Olives" (ēulizeto eis to oros to kaloumenon Elaiōn — was lodging at the mountain called of Olives; aulizomai = to lodge, to spend the night outdoors, to bivouac) — the word suggests sleeping in the open air or under simple shelter rather than in a house. The pattern of daily Temple teaching and nightly Olivet withdrawal summarizes Jesus'' final days of public ministry before the Passover. The Mount of Olives will be the location of his agony (22:39) and his ascension (Acts 1:12).', NULL),
  (38, 'And all the people came early in the morning to him in the temple, for to hear him.', 'καὶ πᾶς ὁ λαὸς ὤρθριζεν πρὸς αὐτὸν ἐν τῷ ἱερῷ ἀκούειν αὐτοῦ.', 'kai pas ho laos ōrthrizen pros auton en tō hierō akouein autou.', '"All the people" (pas ho laos — all the people; laos in Luke often denotes the common people as distinct from the religious leadership) — the popular enthusiasm for Jesus'' teaching contrasts sharply with the hostility of the chief priests and scribes (19:47-48; 20:19). "Came early in the morning" (ōrthrizen — were rising early, were coming at dawn; from orthros/dawn; a verb appearing only here in the NT) — the eagerness of the crowds is indicated by their willingness to arrive at first light. "For to hear him" (akouein autou — to hear him, to listen to him) — the people are drawn to his teaching. This summary forms the narrative bridge to chapter 22: while the people flock to hear Jesus, the chief priests conspire to destroy him (22:1-2). The verse encapsulates Luke''s irony: the doomed Temple is filled with eager listeners; its guardians plot murder.', NULL)
) AS v(verse_number, kjv_text, original_text, transliteration, study_note, doctrinal_note)
WHERE b.name = 'Luke' AND c.chapter_number = 21;

-- LUKE CHAPTER 21 — BACKFILL (word_studies + cross_references)

INSERT INTO word_studies (verse_id, original_word, transliteration, strongs_number, meaning, word_order)
SELECT v.id, w.original_word, w.transliteration, w.strongs_number, w.meaning, w.word_order
FROM verses v JOIN chapters c ON v.chapter_id = c.id
JOIN books b ON c.book_id = b.id
CROSS JOIN (VALUES
  (1, 'γαζοφυλάκιον', 'gazophulakion', 'G1049', 'Treasury; gaza (Persian loan = treasure) + phulakē (guard). The thirteen trumpet-shaped chests in the Women''s Court of the Temple for various offerings. The architectural setting of divine economic inversion.', 1),
  (2, 'πενιχράν', 'penichran', 'G3998', 'Destitute, impoverished; stronger than ptōchos (poor). Found only here in the NT. The widow is not merely poor but in absolute need — precisely the class the Torah commanded the Temple to protect.', 1),
  (2, 'λεπτὰ', 'lepta', 'G3016', 'Lepta (plural of lepton); the smallest bronze coin in circulation, worth 1/128 of a denarius. Mark 12:42 clarifies that two lepta equal one quadrans. Essentially the smallest possible monetary contribution.', 2),
  (4, 'περισσεύοντος', 'perisseuontos', 'G4052', 'Abundance, overflow, surplus; from perissos = exceeding, over and above. The rich gave from what they had in excess. Kingdom economics measures not the deposit but the cost to the giver.', 1),
  (4, 'ὑστερήματος', 'husterēmatos', 'G5303', 'Deficiency, lack, poverty, deficit; from hustereō = to come short, to fall behind. The widow gives not from surplus but from deficit — literal negative balance. The mathematics of grace.', 2),
  (4, 'βίον', 'bion', 'G979', 'Life in the sense of livelihood, means of sustenance (distinct from zōē = life itself). The root of "biology." She gave not merely all her money but her entire means of survival — total sacrifice of her economic life.', 3),
  (5, 'ἀναθήμασιν', 'anathēmasin', 'G334', 'Votive offerings, dedicated gifts; from anatithēmi (to set up/dedicate). Distinct from anathema (curse, Gal 1:8-9), though same root. The golden ornaments, shields, and chains dedicated to the Temple by wealthy donors.', 1),
  (6, 'καταλυθήσεται', 'kataluthēsetai', 'G2647', 'Will be destroyed, demolished, dismantled; kata (down) + luō (to loose). Literally "loosed down." Fulfilled in AD 70 when Titus''s soldiers pried apart stones to retrieve melted gold from the crevices.', 1),
  (8, 'Βλέπετε', 'Blepete', 'G991', 'Watch out, see to it, take heed; present imperative of blepō. The first command of the discourse addresses deception before suffering — the greatest spiritual danger is not persecution but being led astray.', 1),
  (8, 'πλανηθῆτε', 'planēthēte', 'G4105', 'Be led astray, be deceived, wander; from planaō. The root of "planet" (wandering star). False teachers cause spiritual wandering — drift from truth toward invented eschatology.', 2),
  (9, 'ἀκαταστασίας', 'akatastasias', 'G181', 'Disorders, political upheavals, commotions, tumults; a (negative) + katastasis (stable condition). Political anarchy. The 60s AD saw civil war in Rome (Year of the Four Emperors) and revolt in Judea.', 1),
  (9, 'πτοηθῆτε', 'ptoēthēte', 'G4422', 'Be terrified, be startled; ptoeō = to frighten suddenly. Appears only here and 24:37 in the NT. A sudden, paralyzing fear — the discourse warns against eschatological panic.', 2),
  (11, 'σεισμοὶ', 'seismoi', 'G4578', 'Earthquakes; from seiō = to shake. The root of "seismic." Paired with cosmic-sign language throughout the discourse. Historical and typological: both precursors to Jerusalem''s fall and previews of eschatological cosmic disturbance.', 1),
  (11, 'λιμοὶ καὶ λοιμοὶ', 'limoi kai loimoi', 'G3042/G3061', 'Famines and pestilences; the near-homophony creates an assonant pairing — a memorable prophetic couplet. Acts 11:28 records a severe famine under Claudius fulfilling the prediction.', 2),
  (13, 'μαρτύριον', 'marturion', 'G3142', 'Testimony, witness; the root of "martyr." Persecution is theologically reframed as opportunity for witness — the hostile courtroom becomes a pulpit. Acts demonstrates this principle repeatedly.', 1),
  (14, 'προμελετᾶν', 'promeletan', 'G4304', 'Rehearse beforehand, meditate in advance; pro (before) + meletaō (to practice). Found only here in the NT. The prohibition of anxious pre-scripting of one''s defense — higher resource is promised.', 1),
  (14, 'ἀπολογηθῆναι', 'apologēthēnai', 'G626', 'To make a defense; the source of "apology" and "apologetics." A formal legal/forensic defense. The disciples will stand in genuine courtrooms, facing genuine charges — not rhetorical exercises.', 2),
  (15, 'στόμα καὶ σοφίαν', 'stoma kai sophian', 'G4750/G4678', 'Mouth and wisdom; both the organ of speech and the content of what is spoken. Fulfilled in Stephen (Acts 6:10: "they were not able to resist the wisdom and spirit by which he spake").', 1),
  (19, 'ὑπομονῇ', 'hupomonē', 'G5281', 'Patient endurance; hupo (under) + menō (to remain). Not passive resignation but active, resolute bearing-up under pressure. A cardinal NT virtue (Rom 5:3-4; Jas 1:3-4; Rev 2:10).', 1),
  (19, 'κτήσασθε', 'ktēsasthe', 'G2932', 'Gain, acquire, win, take possession of; ktaomai. Endurance is the means by which true life is secured. Some manuscripts read future indicative (ktēsesthe, "you will gain") but the substance is the same.', 2),
  (20, 'στρατοπέδων', 'stratopedōn', 'G4760', 'Armed encampments, armies; stratos (army) + pedon (ground). Found only here in the NT. Luke''s historical specificity: the Roman legions surrounding Jerusalem in AD 66-70.', 1),
  (20, 'ἐρήμωσις', 'erēmōsis', 'G2050', 'Desolation, devastation; erēmos = desert, wilderness. The same word family as Daniel''s "abomination of desolation" (Dan 9:27; 11:31 LXX). Luke interprets Daniel''s prophecy as fulfilled in AD 70.', 2),
  (22, 'ἐκδικήσεως', 'ekdikēseōs', 'G1557', 'Vengeance, vindication, retribution; ek (out) + dikē (justice). The phrase echoes Hos 9:7 and Deut 32:35. Jerusalem''s destruction is framed as covenant judgment, not mere Roman military action.', 1),
  (24, 'αἰχμαλωτισθήσονται', 'aichmalōtisthēsontai', 'G163', 'Will be taken captive; aichmē (spear) + halōtos (captured) = captured at spear-point. Josephus records 97,000 Jewish captives taken from Jerusalem in AD 70 and dispersed throughout the empire.', 1),
  (24, 'καιροὶ ἐθνῶν', 'kairoi ethnōn', 'G2540/G1484', 'Times/seasons of the Gentiles; kairos = appointed time (not chronological duration but qualitative season). A uniquely Lukan phrase implying divinely determined Gentile dominion with a terminus (cf. Rom 11:25).', 2),
  (25, 'συνοχὴ', 'sunochē', 'G4928', 'Anguish, distress, compression; sun (together) + echō (to hold). The feeling of being pressed in from all sides with no release. Only here and 2 Cor 2:4 in the NT.', 1),
  (25, 'ἀπορίᾳ', 'aporia', 'G640', 'Perplexity, bewilderment, helplessness; a (negative) + poros (way, passage). Literally "no way out." Found only here in the NT. The existential helplessness of humanity facing cosmic upheaval.', 2),
  (26, 'ἀποψυχόντων', 'apopsuchontōn', 'G674', 'Fainting away, expiring; apo (from) + psuchō (to breathe). Literally "breathing out of life." Found only here in the NT. A vivid word: humanity literally dying of terror before the advancing cosmic crisis.', 1),
  (26, 'οἰκουμένῃ', 'oikoumenē', 'G3625', 'The inhabited world, the civilized earth; from oikeō (to dwell). A Lukan favorite (Luke 2:1; Acts 11:28; 17:6, 31; 24:5). The scope is universal — no nation escapes.', 2),
  (27, 'νεφέλῃ', 'nephelē', 'G3507', 'Cloud; the theophanic cloud of divine presence (Exod 13:21; 1 Kgs 8:10-11; Luke 9:34-35 at the Transfiguration). Direct allusion to Dan 7:13-14 ("one like the Son of man" with "clouds of heaven").', 1),
  (28, 'ἀνακύψατε', 'anakupsate', 'G352', 'Stand upright, raise yourselves, look up; ana (up) + kuptō (to bend down). The posture of the redeemed: erect, confident, head-raised — the opposite of the fainting terror described in v.26.', 1),
  (28, 'ἀπολύτρωσις', 'apolutrōsis', 'G629', 'Redemption, ransom-liberation, release; apo (from) + lutron (ransom). The eschatological consummation of the redemption already purchased at the cross. Cf. Rom 8:23; Eph 1:14; 4:30.', 2),
  (32, 'γενεὰ', 'genea', 'G1074', 'Generation; can mean (1) contemporaneous generation, (2) a kind/type/race of people (cf. Deut 32:5, 20). The interpretive crux of the discourse — whether "this generation" refers to AD 70 witnesses or a qualitatively defined people.', 1),
  (33, 'παρελεύσονται', 'pareleusontai', 'G3928', 'Will pass away, come to an end; para (beside/by) + erchomai (to come) = to pass by. Heaven and earth are transient; Jesus''s words alone possess the permanence the prophets ascribe to God''s word (Isa 40:8).', 1),
  (34, 'κραιπάλῃ', 'kraipalē', 'G2897', 'Hangover, the aftermath of drinking binges; a medical term for the headache and nausea following excess. Found only here in the NT. Luke''s physician vocabulary appearing.', 1),
  (34, 'μερίμναις βιωτικαῖς', 'merimnais biōtikais', 'G3308/G982', 'Cares/anxieties of daily life; merimna from merizō (to divide — the mind pulled in many directions); biōtikos = pertaining to daily living. The mundane concerns that choke eschatological attention (cf. the seed among thorns, 8:14).', 2),
  (35, 'παγὶς', 'pagis', 'G3803', 'Snare, trap; pēgnumi = to fix, set. The image of a bird-trap (Eccl 9:12; Isa 24:17) that springs shut suddenly. The Day comes upon the unprepared as a trap.', 1),
  (36, 'ἀγρυπνεῖτε', 'agrupneite', 'G69', 'Be sleepless, keep vigil, stay awake; a (negative) + hupnos (sleep). Literally "be without sleep." The strongest NT word for spiritual alertness. A military watch-word.', 1),
  (37, 'ηὐλίζετο', 'ēulizeto', 'G835', 'Was lodging, spending the night outdoors; aulizomai from aulē (courtyard, the open area). Jesus sleeps in the open air on the Mount of Olives rather than in any house — both humble and strategic.', 1),
  (38, 'ὤρθριζεν', 'ōrthrizen', 'G3719', 'Was rising early, was coming at dawn; from orthros (dawn). Found only here in the NT. The people''s dawn eagerness contrasts with the authorities'' nocturnal plotting (22:1-6).', 1)
) AS w(verse_number, original_word, transliteration, strongs_number, meaning, word_order)
WHERE b.name = 'Luke' AND c.chapter_number = 21 AND v.verse_number = w.verse_number
ON CONFLICT DO NOTHING;

